s3 = boto3.client("s3", region_name=AWS_REGION)

url_lock = threading.Lock()
inflight = {}

def is_valid_url(url):
    try:
        parsed = urlparse(url)
        return parsed.scheme in ("http", "https") and bool(parsed.netloc)
    except Exception:
        return False

def normalize_url(url):
    url = url.strip()
    if not re.match(r"^[a-zA-Z][a-zA-Z0-9+\-.]*://", url):
        url = "https://" + url
    return url

def s3_key_for_url(url):
    digest = hashlib.sha256(url.encode("utf-8")).hexdigest()
    return f"{S3_PREFIX}{digest}.png"

def s3_thumb_key_for_url(url):
    digest = hashlib.sha256((url + "|thumb").encode("utf-8")).hexdigest()
    return f"{S3_PREFIX}{digest}.jpg"

def s3_url(key):
    if S3_PUBLIC:
        return f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{key}"
    return None

def upload_to_s3(key, data, content_type):
    extra = {"ContentType": content_type}
    if not S3_PUBLIC:
        extra["ACL"] = "private"
    s3.put_object(Bucket=S3_BUCKET, Key=key, Body=data, **extra)

def get_from_s3(key):
    try:
        obj = s3.get_object(Bucket=S3_BUCKET, Key=key)
        return obj["Body"].read(), obj.get("ContentType", "")
    except ClientError as e:
        code = e.response.get("Error", {}).get("Code", "")
        if code in ("NoSuchKey", "404", "NotFound"):
            return None, None
        raise

def make_thumbnail(image_bytes):
    if Image is None:
        return image_bytes
    with Image.open(io.BytesIO(image_bytes)) as img:
        img = img.convert("RGB")
        img.thumbnail((THUMBNAIL_WIDTH, THUMBNAIL_HEIGHT))
        out = io.BytesIO()
        img.save(out, format="JPEG", quality=85, optimize=True)
        return out.getvalue()

def capture_with_chrome(url):
    if webdriver is None:
        raise RuntimeError("selenium not installed")
    options = ChromeOptions()
    options.add_argument("--headless=new")
