def capture_screenshot(url):
    if USE_PHANTOMJS:
        return capture_with_phantomjs(url)
    return capture_with_chrome(url)

def get_or_create_screenshot(url):
    key = s3_key_for_url(url)
    thumb_key = s3_thumb_key_for_url(url)

    data, ctype = get_from_s3(key)
    if data:
        thumb_data, thumb_ctype = get_from_s3(thumb_key)
        if thumb_data:
            return key, thumb_key, data, thumb_data

    with url_lock:
        if url in inflight:
            event = inflight[url]
        else:
            event = threading.Event()
            inflight[url] = event
            event.clear()
            creator = True
        if "creator" not in locals():
            event.wait(timeout=120)
            data, _ = get_from_s3(key)
            thumb_data, _ = get_from_s3(thumb_key)
            return key, thumb_key, data, thumb_data

    try:
        png = capture_screenshot(url)
        thumb = make_thumbnail(png)
        upload_to_s3(key, png, "image/png")
        upload_to_s3(thumb_key, thumb, "image/jpeg")
        return key, thumb_key, png, thumb
    finally:
        with url_lock:
            ev = inflight.pop(url, None)
            if ev:
                ev.set()

