@app.route("/screenshot", methods=["POST", "GET"])
def screenshot():
    url = request.values.get("url", "")
    if not url:
        return jsonify({"error": "url is required"}), 400
    url = normalize_url(url)
    if not is_valid_url(url):
        return jsonify({"error": "invalid url"}), 400

    try:
        key, thumb_key, full, thumb = get_or_create_screenshot(url)
        response = {
            "url": url,
            "screenshot_key": key,
            "thumbnail_key": thumb_key,
            "screenshot_url": s3_url(key),
            "thumbnail_url": s3_url(thumb_key),
        }
        if not S3_PUBLIC:
            response["screenshot_presigned_url"] = s3.generate_presigned_url(
                "get_object", Params={"Bucket": S3_BUCKET, "Key": key}, ExpiresIn=3600
            )
            response["thumbnail_presigned_url"] = s3.generate_presigned_url(
                "get_object", Params={"Bucket": S3_BUCKET, "Key": thumb_key}, ExpiresIn=3600
            )
        return jsonify(response)
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route("/preview", methods=["GET"])
def preview():
    url = request.args.get("url", "")
    if not url:
        return jsonify({"error": "url is required"}), 400
    url = normalize_url(url)
    if not is_valid_url(url):
        return jsonify({"error": "invalid url"}), 400

    try:
        _, thumb_key, _, thumb = get_or_create_screenshot(url)
        if thumb is None:
            return jsonify({"error": "thumbnail unavailable"}), 500
        return send_file(io.BytesIO(thumb), mimetype="image/jpeg", as_attachment=False, download_name="preview.jpg")
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route("/meta", methods=["GET"])
def meta():
    url = request.args.get("url", "")
    if not url:
        return jsonify({"error": "url is required"}), 400
    url = normalize_url(url)
